// Reformatage du payload pour l'email
const data = $input.first().json;
const webhook = $('Webhook (Matix → n8n)').first().json;

const tenantSlug = webhook.tenant_slug || 'tenant';
const date = new Date().toLocaleDateString('fr-FR');

const html = `
  <h1>Rapport quotidien - ${tenantSlug}</h1>
  <p>Date : ${date}</p>
  <h2>Résumé cash</h2>
  <pre>${JSON.stringify(data, null, 2)}</pre>
  <hr>
  <small>Email envoyé automatiquement via Matix workflows.</small>
`;

return [{
  json: {
    html,
    subject: `[Matix] Rapport quotidien ${tenantSlug} — ${date}`,
    recipients: webhook.recipients || [],
    tenant_slug: tenantSlug
  }
}];
